const { createCanvas } = require\('canvas'\);
const fs = require\('fs'\);

function makeIcon\(size, outPath\) {
  const c = createCanvas\(size, size\);
  const ctx = c.getContext\('2d'\);
  const r = size * 0.2;

  // Background
  ctx.fillStyle = '#0f172a';
  ctx.beginPath\(\);
  ctx.moveTo\(r, 0\);
  ctx.lineTo\(size - r, 0\);
  ctx.quadraticCurveTo\(size, 0, size, r\);
  ctx.lineTo\(size, size - r\);
  ctx.quadraticCurveTo\(size, size, size - r, size\);
  ctx.lineTo\(r, size\);
  ctx.quadraticCurveTo\(0, size, 0, size - r\);
  ctx.lineTo\(0, r\);
  ctx.quadraticCurveTo\(0, 0, r, 0\);
  ctx.fill\(\);

  const cx = size / 2;
  // Clock circle
  ctx.strokeStyle = '#38bdf8';
  ctx.lineWidth = size * 0.03;
  ctx.beginPath\(\);
  ctx.arc\(cx, size * 0.38, size * 0.16, 0, Math.PI * 2\);
  ctx.stroke\(\);

  // Clock hands
  ctx.lineCap = 'round';
  ctx.beginPath\(\);
  ctx.moveTo\(cx, size * 0.22\);
  ctx.lineTo\(cx, size * 0.38\);
  ctx.stroke\(\);
  ctx.beginPath\(\);
  ctx.moveTo\(cx, size * 0.38\);
  ctx.lineTo\(cx + size * 0.1, size * 0.34\);
  ctx.stroke\(\);

  // Pills
  ctx.fillStyle = '#34d399';
  const pw = size * 0.4, ph = size * 0.06, pr = ph / 2;
  ctx.beginPath\(\);
  ctx.roundRect\(cx - pw/2, size * 0.62, pw, ph, pr\);
  ctx.fill\(\);

  ctx.globalAlpha = 0.6;
  const pw2 = size * 0.28;
  ctx.beginPath\(\);
  ctx.roundRect\(cx - pw2/2, size * 0.72, pw2, ph, pr\);
  ctx.fill\(\);

  fs.writeFileSync\(outPath, c.toBuffer\('image/png'\)\);
}

makeIcon\(192, 'public/icon-192.png'\);
makeIcon\(512, 'public/icon-512.png'\);
console.log\('Icons created'\);
